export function formatBytes(bytes: number): string {
  const rounded = Math.round(bytes * 100) / 100;
  return `${rounded} B`;
}

export function formatDuration(ms: number): string {
  const seconds = ms / 1000;
  const rounded = Math.round(seconds * 100) / 100;
  return `${rounded} s`;
}

import { describe, expect, it } from 'vitest';
import { formatBytes, formatDuration } from './formatters.js';

describe('formatBytes', () => {
  it('rounds to two decimal places and appends the unit', () => {
    expect(formatBytes(1024.4567)).toBe('1024.46 B');
  });

  it('formats a whole number without unnecessary decimals', () => {
    expect(formatBytes(2048)).toBe('2048 B');
  });
});

describe('formatDuration', () => {
  it('converts milliseconds to seconds, rounded to two decimal places', () => {
    expect(formatDuration(1234)).toBe('1.23 s');
  });

  it('formats a whole number of seconds without unnecessary decimals', () => {
    expect(formatDuration(5000)).toBe('5 s');
  });
});
